async function ratePost(postId, userId, rating) {
  if (rating < 1 || rating > 5) throw new Error("Rating must be 1-5");
  await pool.query(
    `INSERT INTO report_ratings (post_id, user_id, rating)
     VALUES ($1, $2, $3)
     ON CONFLICT (post_id, user_id)
     DO UPDATE SET rating = $3, updated_at = NOW()`,
    [postId, userId, rating]
  );
  const { rows } = await pool.query(
    `SELECT COALESCE(AVG(rating), 0) AS avg, COUNT(*)::int AS cnt
     FROM report_ratings WHERE post_id = $1`,
    [postId]
  );
  await pool.query(
    `UPDATE report_posts SET rating_average = $1, rating_count = $2, updated_at = NOW()
     WHERE id = $3`,
    [rows[0].avg, rows[0].cnt, postId]
  );
  return { rating, rating_average: Number(rows[0].avg), rating_count: rows[0].cnt };
}
