import { Router as Router3 } from "express";
import multer3 from "multer";

// src/middleware/optionalAuth.ts
import jwt3 from "jsonwebtoken";
function optionalAuth(req, _res, next) {
  const header = req.headers.authorization || "";
  const token = header.startsWith("Bearer ") ? header.slice(7) : null;
  if (!token) {
    req.user = null;
    return next();
  }
  const secret = process.env.JWT_ACCESS_SECRET;
  if (!secret) {
    req.user = null;
    return next();
  }
  try {
    const decoded = jwt3.verify(token, secret);
    if (typeof decoded === "string") {
      req.user = null;
      return next();
    }
    const payload = decoded;
    const rawId = payload.user_id ?? payload.id ?? payload.sub;
    if (rawId == null) {
      console.warn(
        "\u26A0\uFE0F optionalAuth - No user ID in token. Payload keys:",
        Object.keys(payload)
      );
      req.user = null;
      return next();
    }
    const userId = String(rawId);
    if (!userId) {
      req.user = null;
      return next();
    }
    req.user = {
      id: userId,
      email: payload.email || "",
      role: payload.role || "citizen"
    };
    console.log("\u2705 optionalAuth - User authenticated:", req.user.id);
    return next();
  } catch (err) {
    console.warn("\u26A0\uFE0F optionalAuth - Token error:", err.message);
    req.user = null;
    return next();
  }
}

