    const swLat = parseFloat(req.query.swLat);
    const swLng = parseFloat(req.query.swLng);
    const bounds = Number.isFinite(neLat) && Number.isFinite(neLng) && Number.isFinite(swLat) && Number.isFinite(swLng) ? { neLat, neLng, swLat, swLng } : null;
