init_pool();
init_triggers_service();
var VALID_STATUSES = [
  "submitted",
  "under_review",
  "in_progress",
  "resolved",
  "closed"
];
async function updateReportStatusController(req, res) {
  try {
    const reportId = req.params.id;
    const { status, notes } = req.body;
    const userId = req.user?.id;
    if (!reportId || typeof reportId !== "string" || !reportId.trim()) {
      return res.status(400).json({
        success: false,
        error: "Invalid report ID"
      });
    }
    if (!userId) {
      return res.status(401).json({
        success: false,
        error: "Unauthorized"
      });
    }
    if (!status || !VALID_STATUSES.includes(status)) {
      return res.status(400).json({
        success: false,
        error: `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`
      });
    }
    const { rows: reportRows } = await pool.query(`SELECT status FROM reports WHERE id = $1`, [reportId]);
    if (!reportRows.length) {
      return res.status(404).json({
        success: false,
        error: "Report not found"
      });
    }
    const oldStatus = reportRows[0].status;
    if (oldStatus === status) {
      return res.json({
        success: true,
        data: { message: "Status unchanged", status }
      });
    }
    await pool.query(`UPDATE reports SET status = $1 WHERE id = $2`, [
      status,
      reportId
    ]);
    await pool.query(
      `INSERT INTO status_history (report_id, old_status, new_status, changed_by, notes)
       VALUES ($1, $2, $3, $4, $5)`,
      [reportId, oldStatus, status, userId, notes || null]
    );
    try {
      await notifyStatusChange(reportId, status);
    } catch (err) {
      console.error("notifyStatusChange error:", err);
    }
    return res.json({
      success: true,
      data: {
        report_id: reportId,
        old_status: oldStatus,
        new_status: status
      }
    });
  } catch (err) {
    console.error("updateReportStatusController error:", err);
    return res.status(500).json({
      success: false,
      error: "Server error"
    });
  }
}

