async function detectWardFromCoords(req, res, next) {
  try {
    const { lat, lng } = req.query;
    if (!lat || !lng) {
      return res.status(400).json({
        success: false,
        message: "lat and lng query parameters are required"
      });
    }
    const latitude = parseFloat(lat);
    const longitude = parseFloat(lng);
    if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) {
      return res.status(400).json({
        success: false,
        message: "lat and lng must be valid numbers"
      });
    }
    if (latitude < -90 || latitude > 90) {
      return res.status(400).json({
        success: false,
        message: "lat must be between -90 and 90"
      });
    }
    if (longitude < -180 || longitude > 180) {
      return res.status(400).json({
        success: false,
        message: "lng must be between -180 and 180"
      });
    }
    const ward = await detectWard(latitude, longitude);
    if (!ward) {
      const municipality = await detectMunicipality(latitude, longitude);
      if (municipality) {
        return res.status(200).json({
          success: true,
          detected: false,
          ward: null,
          municipality: {
            id: municipality.municipalityId,
            name: municipality.municipalityName,
            code: municipality.municipalityCode
          },
          message: "Ward boundary not mapped yet, but location is within " + municipality.municipalityName + ". Your report will be routed to the municipality for assignment."
        });
      }
      return res.status(200).json({
        success: true,
        detected: false,
        ward: null,
        municipality: null,
        message: "Location is outside all registered boundaries. Your report will still be submitted but may require manual routing."
      });
    }
    return res.status(200).json({
      success: true,
      detected: true,
      ward: {
        id: ward.wardId,
        name: ward.wardName,
        ward_code: ward.wardCode
      }
    });
  } catch (err) {
    next(err);
  }
}
