function requireWardUser(req, res, next) {
  if (!req.user) {
    return res.status(401).json({ ok: false, message: "Unauthorized" });
  }
  if (!req.user.ward_id) {
    return res.status(403).json({
      ok: false,
      message: "Access denied: not a ward user"
    });
  }
  next();
}

