async function listChatPeersController(req, res) {
  try {
    const principal = await principalFromReq(req);
    if (principal.kind !== "officer") {
      return res.status(403).json({ success: false, error: "Officers only" });
    }
    const { pool: pool2 } = await Promise.resolve().then(() => (init_pool(), pool_exports));
    if (principal.wardId) {
      const { rows } = await pool2.query(
        `SELECT o.id, o.first_name, o.last_name,
                o.type::text AS type,
                o.profile_image_url,
                d.name AS department_name
           FROM officers o
           LEFT JOIN officer_departments d ON d.id = o.department_id
          WHERE o.ward_id = $1
            AND o.id <> $2
            AND o.deleted_at IS NULL
          ORDER BY o.first_name, o.last_name`,
        [principal.wardId, principal.id]
      );
      return res.json({ success: true, data: { peers: rows } });
    }
    if (principal.municipalityId) {
      const { rows } = await pool2.query(
        `SELECT o.id, o.first_name, o.last_name,
                o.type::text AS type,
                o.profile_image_url,
                d.name AS department_name
           FROM officers o
           LEFT JOIN wards w ON w.id = o.ward_id
           LEFT JOIN officer_departments d ON d.id = o.department_id
          WHERE (w.municipality_id = $1 OR o.ward_id IS NULL)
            AND o.id <> $2
            AND o.type = 'municipality_officer'
            AND o.deleted_at IS NULL
          ORDER BY o.first_name, o.last_name`,
        [principal.municipalityId, principal.id]
      );
      return res.json({ success: true, data: { peers: rows } });
    }
    return res.json({ success: true, data: { peers: [] } });
  } catch (err) {
    return handleError(res, err);
  }
}
