// src/services/notifications/realtime-delivery.service.ts
init_pool();
var NOTIFICATION_CHANNEL2 = "notification_events";
var PUSH_BRIDGE_LOCK_KEY = 24040101;
var bridgeStarted2 = false;
async function handleNotificationEvent(rawPayload) {
  if (!rawPayload) {
    return;
  }
  let payload;
  try {
    payload = JSON.parse(rawPayload);
  } catch (error) {
    console.error("Failed to parse notification event payload:", error);
    return;
  }
  const notification = payload.notification;
  const recipientId = notification?.user_id ?? notification?.officer_id;
  const recipientRole = notification?.officer_id ? "officer" : "citizen";
  if (payload.action !== "created" || !notification || !recipientId) {
    return;
  }
  try {
    await sendPushNotification(
      recipientId,
      {
        title: notification.title,
        body: notification.message,
        data: {
          notificationId: notification.id,
          reportId: notification.report_id ?? void 0,
          type: notification.type,
          link: notification.link ?? void 0,
          ...notification.metadata ?? {}
        }
      },
      recipientRole
    );
  } catch (error) {
    console.error("Realtime push delivery error:", error);
  }
}
async function startRealtimeNotificationDelivery() {
  if (bridgeStarted2) {
    return;
  }
  const client = await pool.connect();
  try {
    const lockResult = await client.query(
      "SELECT pg_try_advisory_lock($1) AS acquired",
      [PUSH_BRIDGE_LOCK_KEY]
    );
    if (!lockResult.rows[0]?.acquired) {
      client.release();
      console.log(
        "Notification push bridge already active on another backend instance"
      );
      return;
    }
    await client.query(`LISTEN ${NOTIFICATION_CHANNEL2}`);
    client.on("notification", (msg) => {
      void handleNotificationEvent(msg.payload);
    });
    client.on("error", (error) => {
      console.error("Notification push bridge listener error:", error);
    });
    bridgeStarted2 = true;
    console.log(
      `Realtime notification push bridge listening on ${NOTIFICATION_CHANNEL2}`
    );
  } catch (error) {
    client.release();
    throw error;
  }
}

// src/server.ts
var PORT = Number(process.env.PORT || 5e3);
async function startServer() {
  try {
    await pool.query("SELECT 1");
    console.log("Database connection test passed");
    await startRealtimeNotificationDelivery();
    await startChatEventsBridge();
    startSlaChecker();
    const httpServer = createServer(app_default);
    initRealtime(httpServer);
    httpServer.listen(PORT, "0.0.0.0", () => {
      console.log(`Server running on http://0.0.0.0:${PORT}`);
    });
  } catch (error) {
    console.error("Failed to start server", error);
    process.exit(1);
  }
}
startServer();
